import{_ as n,o as t,c as s,a4 as l}from"./chunks/framework._in6GHBg.js";const h=JSON.parse('{"title":"解析几何详解","description":"","frontmatter":{},"headers":[],"relativePath":"math/Math-Learn-Detail-005-解析几何详解-V1.0-20260405.md","filePath":"math/Math-Learn-Detail-005-解析几何详解-V1.0-20260405.md"}'),e={name:"math/Math-Learn-Detail-005-解析几何详解-V1.0-20260405.md"};function i(p,a,r,o,d,c){return t(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="解析几何详解" tabindex="-1">解析几何详解 <a class="header-anchor" href="#解析几何详解" aria-label="Permalink to &quot;解析几何详解&quot;">​</a></h1><p><strong>从&quot;几何直观&quot;到&quot;代数计算&quot;——用方程研究图形</strong></p><hr><h2 id="一、本章地图" tabindex="-1">一、本章地图 <a class="header-anchor" href="#一、本章地图" aria-label="Permalink to &quot;一、本章地图&quot;">​</a></h2><h3 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h3><p>学完本章，你将：</p><ol><li>理解&quot;用代数方法研究几何问题&quot;的思想</li><li>掌握直线、圆的方程及其位置关系</li><li>掌握圆锥曲线（椭圆、双曲线、抛物线）的定义与性质</li></ol><h3 id="知识网络" tabindex="-1">知识网络 <a class="header-anchor" href="#知识网络" aria-label="Permalink to &quot;知识网络&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解析几何</span></span>
<span class="line"><span>├── 直线</span></span>
<span class="line"><span>│   ├── 倾斜角与斜率</span></span>
<span class="line"><span>│   ├── 直线方程的几种形式 ⭐</span></span>
<span class="line"><span>│   └── 两直线位置关系</span></span>
<span class="line"><span>├── 圆</span></span>
<span class="line"><span>│   ├── 圆的标准方程与一般方程 ⭐</span></span>
<span class="line"><span>│   └── 直线与圆的位置关系</span></span>
<span class="line"><span>└── 圆锥曲线</span></span>
<span class="line"><span>    ├── 椭圆 ⭐</span></span>
<span class="line"><span>    │   ├── 定义与标准方程</span></span>
<span class="line"><span>    │   └── 几何性质</span></span>
<span class="line"><span>    ├── 双曲线</span></span>
<span class="line"><span>    │   ├── 定义与标准方程</span></span>
<span class="line"><span>    │   └── 几何性质</span></span>
<span class="line"><span>    ├── 抛物线 ⭐</span></span>
<span class="line"><span>    │   ├── 定义与标准方程</span></span>
<span class="line"><span>    │   └── 几何性质</span></span>
<span class="line"><span>    └── 直线与圆锥曲线的位置关系 ⭐</span></span></code></pre></div><h3 id="前后联系" tabindex="-1">前后联系 <a class="header-anchor" href="#前后联系" aria-label="Permalink to &quot;前后联系&quot;">​</a></h3><ul><li><strong>前置知识</strong>：函数、向量、三角函数</li><li><strong>后续应用</strong>：导数（曲线的切线）、物理（轨道运动）</li><li><strong>跨学科联系</strong>：物理（行星轨道、抛体运动）、天文（开普勒定律）</li></ul><hr><h2 id="二、概念定义" tabindex="-1">二、概念定义 <a class="header-anchor" href="#二、概念定义" aria-label="Permalink to &quot;二、概念定义&quot;">​</a></h2><h3 id="_2-1-直线的方程-⭐" tabindex="-1">2.1 直线的方程 ⭐ <a class="header-anchor" href="#_2-1-直线的方程-⭐" aria-label="Permalink to &quot;2.1 直线的方程 ⭐&quot;">​</a></h3><p><strong>倾斜角</strong>：直线向上的方向与x轴正方向的夹角α，0°≤α&lt;180°</p><p><strong>斜率</strong>：k = tanα（α≠90°）</p><ul><li>两点A(x₁,y₁), B(x₂,y₂)的斜率：k = (y₂-y₁)/(x₂-x₁)</li></ul><p><strong>直线方程的几种形式</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">形式</th><th style="text-align:center;">方程</th><th style="text-align:center;">适用条件</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>点斜式</strong></td><td style="text-align:center;">y-y₀ = k(x-x₀)</td><td style="text-align:center;">已知点和斜率</td></tr><tr><td style="text-align:center;"><strong>斜截式</strong></td><td style="text-align:center;">y = kx+b</td><td style="text-align:center;">已知斜率和y轴截距</td></tr><tr><td style="text-align:center;"><strong>两点式</strong></td><td style="text-align:center;">(y-y₁)/(y₂-y₁) = (x-x₁)/(x₂-x₁)</td><td style="text-align:center;">已知两点</td></tr><tr><td style="text-align:center;"><strong>截距式</strong></td><td style="text-align:center;">x/a + y/b = 1</td><td style="text-align:center;">已知x,y轴截距</td></tr><tr><td style="text-align:center;"><strong>一般式</strong></td><td style="text-align:center;">Ax+By+C = 0</td><td style="text-align:center;">通用形式</td></tr></tbody></table><p><strong>一般式的几何意义</strong>：</p><ul><li>斜率k = -A/B（B≠0）</li><li>法向量n⃗ = (A, B)（垂直于直线的向量）</li></ul><hr><h3 id="_2-2-两直线的位置关系" tabindex="-1">2.2 两直线的位置关系 <a class="header-anchor" href="#_2-2-两直线的位置关系" aria-label="Permalink to &quot;2.2 两直线的位置关系&quot;">​</a></h3><p>设l₁: A₁x+B₁y+C₁=0，l₂: A₂x+B₂y+C₂=0</p><table tabindex="0"><thead><tr><th style="text-align:center;">位置关系</th><th style="text-align:left;">条件</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>平行</strong></td><td style="text-align:left;">A₁B₂ = A₂B₁ 且 B₁C₂ ≠ B₂C₁</td></tr><tr><td style="text-align:center;"><strong>垂直</strong></td><td style="text-align:left;">A₁A₂ + B₁B₂ = 0（斜率乘积为-1）</td></tr><tr><td style="text-align:center;"><strong>相交</strong></td><td style="text-align:left;">A₁B₂ ≠ A₂B₁</td></tr><tr><td style="text-align:center;"><strong>重合</strong></td><td style="text-align:left;">A₁/A₂ = B₁/B₂ = C₁/C₂</td></tr></tbody></table><p><strong>点到直线距离</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>d = |Ax₀+By₀+C| / √(A²+B²)</span></span></code></pre></div><hr><h3 id="_2-3-圆的方程-⭐" tabindex="-1">2.3 圆的方程 ⭐ <a class="header-anchor" href="#_2-3-圆的方程-⭐" aria-label="Permalink to &quot;2.3 圆的方程 ⭐&quot;">​</a></h3><p><strong>标准方程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(x-a)² + (y-b)² = r²</span></span></code></pre></div><ul><li>圆心(a, b)，半径r</li></ul><p><strong>一般方程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x² + y² + Dx + Ey + F = 0</span></span></code></pre></div><ul><li>配方得标准形式：(x+D/2)² + (y+E/2)² = (D²+E²-4F)/4</li><li>当D²+E²-4F &gt; 0时表示圆</li></ul><p><strong>直线与圆的位置关系</strong>：</p><ul><li><strong>几何法</strong>：比较圆心到直线距离d与半径r <ul><li>d &lt; r：相交（2个交点）</li><li>d = r：相切（1个交点）</li><li>d &gt; r：相离（0个交点）</li></ul></li><li><strong>代数法</strong>：联立方程，看判别式Δ</li></ul><hr><h3 id="_2-4-椭圆-⭐" tabindex="-1">2.4 椭圆 ⭐ <a class="header-anchor" href="#_2-4-椭圆-⭐" aria-label="Permalink to &quot;2.4 椭圆 ⭐&quot;">​</a></h3><p><strong>定义</strong>：平面内到两定点F₁, F₂的距离之和为常数2a的点的轨迹</p><ul><li>2a &gt; |F₁F₂| = 2c（否则不是椭圆）</li></ul><p><strong>标准方程</strong>：</p><ul><li>焦点在x轴：x²/a² + y²/b² = 1（a &gt; b &gt; 0）</li><li>焦点在y轴：y²/a² + x²/b² = 1（a &gt; b &gt; 0）</li></ul><p><strong>参数关系</strong>：</p><ul><li>a：半长轴，b：半短轴，c：半焦距</li><li><strong>c² = a² - b²</strong></li><li>离心率：e = c/a（0 &lt; e &lt; 1）</li></ul><p><strong>几何性质</strong>：</p><ul><li>范围：|x|≤a, |y|≤b（焦点在x轴时）</li><li>对称性：关于x轴、y轴、原点对称</li><li>顶点：(±a, 0), (0, ±b)</li></ul><hr><h3 id="_2-5-双曲线" tabindex="-1">2.5 双曲线 <a class="header-anchor" href="#_2-5-双曲线" aria-label="Permalink to &quot;2.5 双曲线&quot;">​</a></h3><p><strong>定义</strong>：平面内到两定点F₁, F₂的距离之差的绝对值为常数2a的点的轨迹</p><ul><li>2a &lt; |F₁F₂| = 2c</li></ul><p><strong>标准方程</strong>：</p><ul><li>焦点在x轴：x²/a² - y²/b² = 1</li><li>焦点在y轴：y²/a² - x²/b² = 1</li></ul><p><strong>参数关系</strong>：</p><ul><li><strong>c² = a² + b²</strong>（注意是+号，不是-号）</li><li>离心率：e = c/a（e &gt; 1）</li><li>渐近线：y = ±(b/a)x（焦点在x轴时）</li></ul><hr><h3 id="_2-6-抛物线-⭐" tabindex="-1">2.6 抛物线 ⭐ <a class="header-anchor" href="#_2-6-抛物线-⭐" aria-label="Permalink to &quot;2.6 抛物线 ⭐&quot;">​</a></h3><p><strong>定义</strong>：平面内到一定点F（焦点）和定直线l（准线）距离相等的点的轨迹</p><p><strong>标准方程</strong>（四种形式）：</p><table tabindex="0"><thead><tr><th style="text-align:center;">方程</th><th style="text-align:center;">焦点</th><th style="text-align:center;">准线</th><th style="text-align:center;">开口方向</th></tr></thead><tbody><tr><td style="text-align:center;">y² = 2px (p&gt;0)</td><td style="text-align:center;">(p/2, 0)</td><td style="text-align:center;">x = -p/2</td><td style="text-align:center;">向右</td></tr><tr><td style="text-align:center;">y² = -2px (p&gt;0)</td><td style="text-align:center;">(-p/2, 0)</td><td style="text-align:center;">x = p/2</td><td style="text-align:center;">向左</td></tr><tr><td style="text-align:center;">x² = 2py (p&gt;0)</td><td style="text-align:center;">(0, p/2)</td><td style="text-align:center;">y = -p/2</td><td style="text-align:center;">向上</td></tr><tr><td style="text-align:center;">x² = -2py (p&gt;0)</td><td style="text-align:center;">(0, -p/2)</td><td style="text-align:center;">y = p/2</td><td style="text-align:center;">向下</td></tr></tbody></table><p><strong>核心性质</strong>：抛物线上任一点到焦点的距离等于到准线的距离</p><hr><h3 id="_2-7-直线与圆锥曲线的位置关系-⭐" tabindex="-1">2.7 直线与圆锥曲线的位置关系 ⭐ <a class="header-anchor" href="#_2-7-直线与圆锥曲线的位置关系-⭐" aria-label="Permalink to &quot;2.7 直线与圆锥曲线的位置关系 ⭐&quot;">​</a></h3><p><strong>通用方法</strong>：</p><ol><li>设直线方程：y = kx + m 或 x = my + n</li><li>联立圆锥曲线方程</li><li>消元得一元二次方程</li><li>用判别式Δ判断交点个数</li><li>用韦达定理求交点关系</li></ol><p><strong>弦长公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>|AB| = √(1+k²) · |x₁-x₂| = √(1+k²) · √Δ/|a|</span></span></code></pre></div><p><strong>设点设线策略</strong>：</p><ul><li><strong>设点</strong>：用参数表示曲线上一点（如椭圆上的点(acosθ, bsinθ)）</li><li><strong>设线</strong>：y = kx + m（斜率存在时）或x = my + n（斜率不存在或需简化计算时）</li></ul><hr><h2 id="三、典型例题" tabindex="-1">三、典型例题 <a class="header-anchor" href="#三、典型例题" aria-label="Permalink to &quot;三、典型例题&quot;">​</a></h2><h3 id="例题1-求圆的方程" tabindex="-1">例题1：求圆的方程 <a class="header-anchor" href="#例题1-求圆的方程" aria-label="Permalink to &quot;例题1：求圆的方程&quot;">​</a></h3><p><strong>题目</strong>：求过点A(1,2), B(3,4)，圆心在直线x-y+1=0上的圆的方程。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>设圆心(a,b)，则：</span></span>
<span class="line"><span>① (a-1)²+(b-2)² = (a-3)²+(b-4)²  【到A、B距离相等】</span></span>
<span class="line"><span>② a-b+1 = 0  【圆心在给定直线上】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>由①：展开化简得 a+b=5</span></span>
<span class="line"><span>由②：a-b=-1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解得：a=2, b=3</span></span>
<span class="line"><span>半径r = √[(2-1)²+(3-2)²] = √2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ 圆的方程：(x-2)²+(y-3)² = 2</span></span></code></pre></div><hr><h3 id="例题2-椭圆方程与性质" tabindex="-1">例题2：椭圆方程与性质 <a class="header-anchor" href="#例题2-椭圆方程与性质" aria-label="Permalink to &quot;例题2：椭圆方程与性质&quot;">​</a></h3><p><strong>题目</strong>：椭圆中心在原点，焦点在x轴，离心率e=1/2，且过点(2,3)，求椭圆方程。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>设椭圆方程：x²/a² + y²/b² = 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>已知：</span></span>
<span class="line"><span>① e = c/a = 1/2 → c = a/2</span></span>
<span class="line"><span>② c² = a² - b² → a²/4 = a² - b² → b² = 3a²/4</span></span>
<span class="line"><span>③ 过点(2,3)：4/a² + 9/b² = 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>将b²=3a²/4代入③：</span></span>
<span class="line"><span>4/a² + 9/(3a²/4) = 1</span></span>
<span class="line"><span>4/a² + 12/a² = 1</span></span>
<span class="line"><span>16/a² = 1</span></span>
<span class="line"><span>∴ a²=16, b²=12</span></span>
<span class="line"><span></span></span>
<span class="line"><span>椭圆方程：x²/16 + y²/12 = 1</span></span></code></pre></div><hr><h3 id="例题3-直线与椭圆相交" tabindex="-1">例题3：直线与椭圆相交 <a class="header-anchor" href="#例题3-直线与椭圆相交" aria-label="Permalink to &quot;例题3：直线与椭圆相交&quot;">​</a></h3><p><strong>题目</strong>：直线y=x+1与椭圆x²/4+y²=1相交于A,B两点，求弦长|AB|。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>联立：</span></span>
<span class="line"><span>x²/4 + (x+1)² = 1</span></span>
<span class="line"><span>x²/4 + x²+2x+1 = 1</span></span>
<span class="line"><span>5x²/4 + 2x = 0</span></span>
<span class="line"><span>5x² + 8x = 0</span></span>
<span class="line"><span>x(5x+8) = 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ x₁=0, x₂=-8/5</span></span>
<span class="line"><span>对应y₁=1, y₂=-3/5</span></span>
<span class="line"><span></span></span>
<span class="line"><span>弦长|AB| = √[(x₂-x₁)²+(y₂-y₁)²]</span></span>
<span class="line"><span>         = √[(64/25)+(64/25)]</span></span>
<span class="line"><span>         = √(128/25) = 8√2/5</span></span></code></pre></div><p><strong>或用弦长公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>联立后：5x²+8x=0</span></span>
<span class="line"><span>Δ = 64</span></span>
<span class="line"><span>|AB| = √(1+1)·√64/5 = √2·8/5 = 8√2/5</span></span></code></pre></div><hr><h2 id="四、配套练习" tabindex="-1">四、配套练习 <a class="header-anchor" href="#四、配套练习" aria-label="Permalink to &quot;四、配套练习&quot;">​</a></h2><h3 id="基础练习-必做" tabindex="-1">基础练习（必做） <a class="header-anchor" href="#基础练习-必做" aria-label="Permalink to &quot;基础练习（必做）&quot;">​</a></h3><p><strong>练习1</strong>：求过点(1,2)和(3,0)的直线方程。</p><p><strong>练习2</strong>：求圆心为(2,-1)，且与直线3x-4y+5=0相切的圆的方程。</p><p><strong>练习3</strong>：椭圆x²/25+y²/9=1的焦点坐标是？离心率是？</p><p><strong>练习4</strong>：抛物线y²=8x的焦点坐标是？准线方程是？</p><p><strong>参考答案</strong>：</p><ul><li>练习1：x+y-3=0（或y=-x+3）</li><li>练习2：(x-2)²+(y+1)²=4（距离d=|6+4+5|/5=3，半径应为3？重新算：d=|6+4+5|/5=3，方程为(x-2)²+(y+1)²=9）</li><li>练习3：焦点(±4,0)，离心率e=4/5</li><li>练习4：焦点(2,0)，准线x=-2</li></ul><hr><h3 id="提高练习-选做" tabindex="-1">提高练习（选做） <a class="header-anchor" href="#提高练习-选做" aria-label="Permalink to &quot;提高练习（选做）&quot;">​</a></h3><p><strong>练习5</strong>：椭圆x²/a²+y²/b²=1(a&gt;b&gt;0)的离心率为√3/2，且过点(2,1)，求椭圆方程。</p><p><strong>练习6</strong>：直线y=kx+1与双曲线x²-y²=1交于A,B两点，若|AB|=4√2，求k的值。</p><hr><h2 id="五、faq常见问题" tabindex="-1">五、FAQ常见问题 <a class="header-anchor" href="#五、faq常见问题" aria-label="Permalink to &quot;五、FAQ常见问题&quot;">​</a></h2><h3 id="faq-1-椭圆和双曲线的a-b-c关系总记混" tabindex="-1">FAQ 1：椭圆和双曲线的a,b,c关系总记混 <a class="header-anchor" href="#faq-1-椭圆和双曲线的a-b-c关系总记混" aria-label="Permalink to &quot;FAQ 1：椭圆和双曲线的a,b,c关系总记混&quot;">​</a></h3><p><strong>记忆方法</strong>：</p><ul><li><strong>椭圆</strong>：a最大，c²=a²-b²（减号）</li><li><strong>双曲线</strong>：c最大，c²=a²+b²（加号）</li></ul><p><strong>口诀</strong>：</p><ul><li>椭圆：a是老大，c²=a²-b²</li><li>双曲线：c是老大，c²=a²+b²</li></ul><hr><h3 id="faq-2-抛物线方程四种形式总搞混" tabindex="-1">FAQ 2：抛物线方程四种形式总搞混 <a class="header-anchor" href="#faq-2-抛物线方程四种形式总搞混" aria-label="Permalink to &quot;FAQ 2：抛物线方程四种形式总搞混&quot;">​</a></h3><p><strong>判断方法</strong>：</p><ul><li>看x²还是y²：x²→开口上下，y²→开口左右</li><li>看系数正负：正→向正方向，负→向负方向</li></ul><p><strong>示例</strong>：</p><ul><li>y²=4x：y²→左右，正→向右</li><li>x²=-8y：x²→上下，负→向下</li></ul><hr><h3 id="faq-3-直线与圆锥曲线联立计算量大" tabindex="-1">FAQ 3：直线与圆锥曲线联立计算量大 <a class="header-anchor" href="#faq-3-直线与圆锥曲线联立计算量大" aria-label="Permalink to &quot;FAQ 3：直线与圆锥曲线联立计算量大&quot;">​</a></h3><p><strong>简化技巧</strong>：</p><ol><li><strong>设线方式</strong>：若过x轴上定点，设x=my+n可能更简单</li><li><strong>韦达定理</strong>：不求具体根，用x₁+x₂和x₁x₂表示</li><li><strong>整体代入</strong>：弦长、面积等常用整体式表示</li></ol><hr><h3 id="faq-4-怎么判断设点还是设线" tabindex="-1">FAQ 4：怎么判断设点还是设线 <a class="header-anchor" href="#faq-4-怎么判断设点还是设线" aria-label="Permalink to &quot;FAQ 4：怎么判断设点还是设线&quot;">​</a></h3><p><strong>设点</strong>：</p><ul><li>问题涉及曲线上一个动点</li><li>用参数表示（如椭圆(acosθ,bsinθ)）</li></ul><p><strong>设线</strong>：</p><ul><li>问题涉及直线与曲线相交</li><li>联立方程求交点关系</li></ul><hr><h2 id="六、本章检查清单" tabindex="-1">六、本章检查清单 <a class="header-anchor" href="#六、本章检查清单" aria-label="Permalink to &quot;六、本章检查清单&quot;">​</a></h2><ul><li>[ ] 能根据条件写出直线方程（各种形式）</li><li>[ ] 能判断两直线位置关系（平行、垂直、相交）</li><li>[ ] 能写出圆的标准方程和一般方程</li><li>[ ] 能判断直线与圆的位置关系</li><li>[ ] 掌握椭圆、双曲线、抛物线的定义和标准方程</li><li>[ ] 能根据条件求椭圆、双曲线、抛物线方程</li><li>[ ] 掌握直线与圆锥曲线相交问题的解法（联立、韦达）</li></ul><hr><p><strong>文档编号</strong>: Math-Learn-Detail-005<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,128)])])}const x=n(e,[["render",i]]);export{h as __pageData,x as default};
